Rule.Source:
        
import sailpoint.object.Identity;
import sailpoint.object.Custom;
import org.apache.commons.logging.Log;
import org.apache.commons.logging.LogFactory;
import sailpoint.tools.Util;
  
 
String LOG_NAME = "org.ascn.rule.ASCN-Azure-O365-Licenses-Escalation";
info(LOG_NAME,"Entering "+LOG_NAME);

List MGR_LEVELS= new ArrayList();
MGR_LEVELS.add("10");
MGR_LEVELS.add("11");
MGR_LEVELS.add("12");

String MGR_LEVEL_ATTR = "managerLevel"; 
 
String newOwnerName = null;

Identity defaultOwnerObj = context.getObjectByName(Identity.class, "Azure Escalations");
String defaultOwner = defaultOwnerObj.getName(); 
  
Identity certOwnerObj = context.getObjectByName(Identity.class, "O365 License Certifiers");
String certOwner = certOwnerObj.getName(); 

if(null != item){	
    //Get the current owner
  	Identity idNewOwner = item.getOwner();  
  if(idNewOwner != null) {
    //If the owner is the default cert owner, do not send escalation to their manager
    if(item.getOwner().getName().equalsIgnoreCase(certOwner)) {
      newOwnerName = idNewOwner.getName();
      
    } else if(!idNewOwner.isInactive() @and idNewOwner.getManager() != null) { // Check if owner is inactive and owner manager is not null
      
      String newOwnerManagerName = idNewOwner.getManager().getName();
      Identity identity = context.getObjectByName(Identity.class, newOwnerManagerName);
			Object certifierMgrLevel = identity.getAttribute(MGR_LEVEL_ATTR);  // identify owner manager level
      //if owner's manager level is not 10, 11 or 12 then escalate to that manager
      if(certifierMgrLevel !=null @and !MGR_LEVELS.contains(certifierMgrLevel.toString())) {
				newOwnerName = idNewOwner.getManager().getName();
      } else {
        //re-assign the cert to the default cert owner
        newOwnerName =certOwnerObj.getName();
      }
    }       
   
  }
}
	  
  info(LOG_NAME,"Exiting "+LOG_NAME);
  if (newOwnerName == null){
    return defaultOwner;
  }
  else{
    return newOwnerName;
  }
